const { ethers } = require('ethers');
const crypto = require('crypto');

class SecureWalletManager {
  constructor() {
    this.encryptedWallets = new Map();
    this.activeWallets = new Map();
    this.sessionTimeout = 300000;
  }

  encryptPrivateKey(privateKey, password) {
    const algorithm = 'aes-256-gcm';
    const salt = crypto.randomBytes(16);
    const key = crypto.pbkdf2Sync(password, salt, 100000, 32, 'sha256');
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(algorithm, key, iv);
    
    let encrypted = cipher.update(privateKey, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();
    
    return {
      encrypted,
      salt: salt.toString('hex'),
      iv: iv.toString('hex'),
      authTag: authTag.toString('hex')
    };
  }

  decryptPrivateKey(encryptedData, password) {
    const algorithm = 'aes-256-gcm';
    const key = crypto.pbkdf2Sync(
      password,
      Buffer.from(encryptedData.salt, 'hex'),
      100000,
      32,
      'sha256'
    );
    
    const decipher = crypto.createDecipheriv(
      algorithm,
      key,
      Buffer.from(encryptedData.iv, 'hex')
    );
    
    decipher.setAuthTag(Buffer.from(encryptedData.authTag, 'hex'));
    
    let decrypted = decipher.update(encryptedData.encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    
    return decrypted;
  }

  storeWallet(walletId, privateKey, password) {
    const encryptedData = this.encryptPrivateKey(privateKey, password);
    this.encryptedWallets.set(walletId, encryptedData);
  }

  loadWallet(walletId, password, provider) {
    const encryptedData = this.encryptedWallets.get(walletId);
    if (!encryptedData) {
      throw new Error('Wallet not found');
    }
    
    const privateKey = this.decryptPrivateKey(encryptedData, password);
    const wallet = new ethers.Wallet(privateKey, provider);
    
    const sessionId = crypto.randomBytes(16).toString('hex');
    this.activeWallets.set(sessionId, {
      wallet,
      timestamp: Date.now()
    });
    
    setTimeout(() => {
      this.activeWallets.delete(sessionId);
    }, this.sessionTimeout);
    
    return sessionId;
  }

  getWallet(sessionId) {
    const session = this.activeWallets.get(sessionId);
    if (!session) {
      throw new Error('Session expired or invalid');
    }
    
    if (Date.now() - session.timestamp > this.sessionTimeout) {
      this.activeWallets.delete(sessionId);
      throw new Error('Session expired');
    }
    
    session.timestamp = Date.now();
    return session.wallet;
  }

  closeSession(sessionId) {
    this.activeWallets.delete(sessionId);
  }
}

class DAppBackend {
  constructor(rpcUrl) {
    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    this.walletManager = new SecureWalletManager();
  }

  async sendETH(sessionId, toAddress, amountInEther) {
    try {
      const wallet = this.walletManager.getWallet(sessionId);
      
      const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString())
      };
      
      const transaction = await wallet.sendTransaction(tx);
      const receipt = await transaction.wait();
      
      return {
        success: true,
        transactionHash: receipt.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async getBalance(address) {
    try {
      const balance = await this.provider.getBalance(address);
      return {
        success: true,
        balance: ethers.formatEther(balance),
        balanceWei: balance.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async interactWithContract(sessionId, contractAddress, abi, methodName, params = [], value = '0') {
    try {
      const wallet = this.walletManager.getWallet(sessionId);
      const contract = new ethers.Contract(contractAddress, abi, wallet);
      
      const options = value !== '0' ? { value: ethers.parseEther(value) } : {};
      
      const tx = await contract[methodName](...params, options);
      const receipt = await tx.wait();
      
      return {
        success: true,
        transactionHash: receipt.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async callContractView(contractAddress, abi, methodName, params = []) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.provider);
      const result = await contract[methodName](...params);
      
      return {
        success: true,
        result: result.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async estimateGas(sessionId, toAddress, amountInEther) {
    try {
      const wallet = this.walletManager.getWallet(sessionId);
      
      const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString())
      };
      
      const gasEstimate = await wallet.estimateGas(tx);
      const feeData = await this.provider.getFeeData();
      
      return {
        success: true,
        gasLimit: gasEstimate.toString(),
        maxFeePerGas: feeData.maxFeePerGas?.toString(),
        maxPriorityFeePerGas: feeData.maxPriorityFeePerGas?.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async getTransactionStatus(txHash) {
    try {
      const receipt = await this.provider.getTransactionReceipt(txHash);
      
      if (!receipt) {
        return {
          success: true,
          status: 'pending'
        };
      }
      
      return {
        success: true,
        status: receipt.status === 1 ? 'confirmed' : 'failed',
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  createWallet(walletId, password) {
    const wallet = ethers.Wallet.createRandom();
    this.walletManager.storeWallet(walletId, wallet.privateKey, password);
    
    return {
      success: true,
      address: wallet.address,
      mnemonic: wallet.mnemonic.phrase
    };
  }

  importWallet(walletId, privateKey, password) {
    try {
      const wallet = new ethers.Wallet(privateKey);
      this.walletManager.storeWallet(walletId, privateKey, password);
      
      return {
        success: true,
        address: wallet.address
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  unlockWallet(walletId, password) {
    try {
      const sessionId = this.walletManager.loadWallet(walletId, password, this.provider);
      const wallet = this.walletManager.getWallet(sessionId);
      
      return {
        success: true,
        sessionId,
        address: wallet.address
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  lockWallet(sessionId) {
    this.walletManager.closeSession(sessionId);
    return {
      success: true,
      message: 'Wallet locked successfully'
    };
  }
}

const ERC20_ABI = [
  'function transfer(address to, uint256 amount) returns (bool)',
  'function balanceOf(address account) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function decimals() view returns (uint8)',
  'function symbol() view returns (string)',
  'function name() view returns (string)'
];

class TokenService extends DAppBackend {
  async transferToken(sessionId, tokenAddress, toAddress, amount) {
    return await this.interactWithContract(
      sessionId,
      tokenAddress,
      ERC20_ABI,
      'transfer',
      [toAddress, amount]
    );
  }

  async getTokenBalance(tokenAddress, ownerAddress) {
    return await this.callContractView(
      tokenAddress,
      ERC20_ABI,
      'balanceOf',
      [ownerAddress]
    );
  }

  async approveToken(sessionId, tokenAddress, spenderAddress, amount) {
    return await this.interactWithContract(
      sessionId,
      tokenAddress,
      ERC20_ABI,
      'approve',
      [spenderAddress, amount]
    );
  }

  async getTokenInfo(tokenAddress) {
    try {
      const name = await this.callContractView(tokenAddress, ERC20_ABI, 'name');
      const symbol = await this.callContractView(tokenAddress, ERC20_ABI, 'symbol');
      const decimals = await this.callContractView(tokenAddress, ERC20_ABI, 'decimals');
      
      return {
        success: true,
        name: name.result,
        symbol: symbol.result,
        decimals: decimals.result
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }
}

